const state = { project: null, results: {}, activeCheck: 'all', activeView: 'overview', selectedIssueId: null, ignoredIssueIds: new Set(), fixedByCodexIssues: new Map(), disabledCheckIds: new Set(), progress: {}, recent: [], scanning: false, loadingLabel: '', fixedCount: 0, overview: null, overviewLoading: false, timeMachine: null, timeMachineLoading: false, evolutionForecast: null, evolutionForecastLoading: false, awards: null, awardsLoading: false, codexChatMessages: [], codexChatMode: 'ask', codexChatBusy: false, codexChatLog: [], showRestorationPreview: false, packageInfo: null, packageLoading: false, packageActionId: null, packageMessage: '', codexFixId: null, codexLog: [], codexResult: null, commitInsight: null, commitLoadingId: null, rescue: { before: null, briefCopied: false } };
