const allIssues = () => Object.entries(state.results).filter(([checkId]) => !state.disabledCheckIds.has(checkId)).flatMap(([, issues]) => issues);
const filteredIssues = () => state.activeCheck === 'all' ? allIssues() : allIssues().filter(issue => issue.type === state.activeCheck);
function updateLiveScanUI() {
  const status = document.querySelector('.repo-status');
  if (status) {
    status.className = 'repo-status is-running';
    status.innerHTML = `${icon('spinner', 13)} Analyzing`;
  }
  const label = document.querySelector('.loading-label');
  if (label) label.innerHTML = `${icon('spinner', 14)} ${esc(state.loadingLabel || 'Analyzing project...')}`;
  const findingCount = document.querySelector('[data-view="findings"] span');
  if (findingCount) findingCount.textContent = String(allIssues().length);
  if (state.activeView === 'overview') {
    const summary = document.querySelector('.finding-summary');
    if (summary) {
      const total = allIssues().length;
      const checks = state.project.checks.filter(check => !state.disabledCheckIds.has(check.id)).length;
      const value = summary.querySelector('strong');
      const detail = summary.querySelector('small');
      if (value) value.textContent = String(total);
      if (detail) detail.textContent = `Scanning in progress · ${checks} active checks`;
    }
  }
}

function renderIntro() { app.innerHTML = `${header()}<main class="intro"><div class="intro-lockup">${logo('intro-logo')}</div><h1>Keep the code.<br>Lose the clutter.</h1><p>Code Redox turns static-analysis signals into a practical cleanup plan: find the risk, understand its context, make one focused change, then verify it with a fresh scan.</p><div class="intro-notes"><span>${icon('check', 14)} Local-first analysis</span><span>${icon('check', 14)} Git-aware evidence</span><span>${icon('check', 14)} You stay in control of changes</span></div><button class="btn btn-primary" id="continue">Get started ${icon('arrow')}</button></main>`; document.querySelector('#continue').onclick = async () => { await window.api.finishIntro(); renderHome(); }; }
