function commitDiffMarkup(patch, focusFile, focusLine) { let oldLine = 0; let newLine = 0; let currentFile = ''; return patch.split(/\r?\n/).map(line => { const diffFile = line.match(/^diff --git a\/(.*?) b\/(.*)$/); if (diffFile) { currentFile = diffFile[2]; return `<div class="commit-diff-meta commit-diff-file" data-diff-file="${esc(currentFile)}">${esc(line)}</div>`; } const hunk = line.match(/^@@ -(\d+)(?:,\d+)? \+(\d+)(?:,\d+)? @@/); if (hunk) { oldLine = Number(hunk[1]); newLine = Number(hunk[2]); return `<div class="commit-diff-hunk">${esc(line)}</div>`; } const file = line.match(/^\+\+\+ b\/(.*)$/); if (file) currentFile = file[1]; if (/^(?:index |--- |\+\+\+ |new file mode|deleted file mode|similarity index|rename (?:from|to) )/.test(line)) return `<div class="commit-diff-meta">${esc(line)}</div>`; if (line.startsWith('+')) { const lineNumber = newLine++; const focus = currentFile === focusFile && lineNumber === focusLine ? ' is-finding-line' : ''; return `<div class="commit-diff-line addition${focus}"><span></span><span>${lineNumber}</span><code>${esc(line)}</code></div>`; } if (line.startsWith('-')) return `<div class="commit-diff-line deletion"><span>${oldLine++}</span><span></span><code>${esc(line)}</code></div>`; if (line.startsWith(' ')) { const oldNumber = oldLine++; const newNumber = newLine++; const focus = currentFile === focusFile && newNumber === focusLine ? ' is-finding-line' : ''; return `<div class="commit-diff-line${focus}"><span>${oldNumber}</span><span>${newNumber}</span><code>${esc(line)}</code></div>`; } return `<div class="commit-diff-meta">${esc(line)}</div>`; }).join(''); }
